input.new_string:
const scaleRowHorizontally = (row: string, scaleFactor: number): string => {
  const characters = row.split("");
  const scaledCharacters = characters.map((char) => char.repeat(scaleFactor));
  return scaledCharacters.join("");
};

export function scalePixelArt(image: string[], scaleFactor: number): string[] {
  return image.map((row) => scaleRowHorizontally(row, scaleFactor));
}

